const MOBILE_WIDTH_BREAKPOINT=768;function getBrowserWidth(){return window.innerWidth||document.documentElement.clientWidth||document.body.clientWidth}function checkMobileDevice(){const userAgent=navigator.userAgent.toLowerCase();return userAgent.includes("mobile")||userAgent.includes("android")||userAgent.includes("iphone")}function isAppEnvironment(){const userAgent=navigator.userAgent.toLowerCase();const isAndroidApp=window.Android!==undefined||window.webkit&&window.webkit.messageHandlers&&window.webkit.messageHandlers.Android;const isIosApp=window.webkit&&window.webkit.messageHandlers&&window.webkit.messageHandlers.callbackHandler;return isAndroidApp||isIosApp}function checkIsMobile(){const currentWidth=getBrowserWidth();const isMobileDevice=checkMobileDevice();return currentWidth<MOBILE_WIDTH_BREAKPOINT||isMobileDevice}(function(){function redirectTraffic(){const currentPath=window.location.pathname;console.log("currentPath ::: "+currentPath);if(currentPath==="/"){return false}const isMobile=checkIsMobile();const hasMobileUrl=currentPath.includes("/mobile/m/");console.log("isMobile ::: "+isMobile);if(isMobile&&!hasMobileUrl){window.location.href=window._contextPath+"/mobile/m"+currentPath.replace(window._contextPath,"");return true}if(!isMobile&&hasMobileUrl){window.location.href=currentPath.replace("/mobile/m","");return true}return false}const isRedirected=redirectTraffic();if(!isRedirected){$(document).ready(function(){$(document).ajaxError(function(event,xhr,options,exc){if(xhr.status===401){if(options.url.indexOf("/auth/login")!==-1){return}alert("로그인 유효시간이 만료되었습니다.\n안전한 이용을 위해 로그인 페이지로 이동합니다.");window.location.href=window._contextPath+"/logout"}})})}})();$(document).ready(function(){});